async function dc(n){var s=await db.collection(n).get();if(s.empty)return 0;var b=db.batch(),c=0,t=0;for(var i=0;i<s.docs.length;i++){b.delete(s.docs[i].ref);c++;t++;if(c>=490){await b.commit();b=db.batch();c=0;}}if(c>0)await b.commit();return t;}
async function bw(col,items,idf){var b=db.batch(),c=0;for(var i=0;i<items.length;i++){var it=items[i];var id=idf(it);var d=Object.assign({},it);delete d.id;b.set(db.collection(col).doc(id),d);c++;if(c>=490){await b.commit();b=db.batch();c=0;process.stdout.write(".");}}if(c>0)await b.commit();}
async function run(){
  console.log("Deleting...");
  console.log("  students:"+await dc("students")+" payments:"+await dc("payments")+" families:"+await dc("Familias"));
  console.log("Uploading "+students.length+" students...");
  await bw("students",students,function(s){return String(s.legajo);});console.log(" OK");
  console.log("Uploading "+families.length+" families...");
  await bw("Familias",families,function(f){return f.id;});console.log(" OK");
  console.log("Uploading "+payments.length+" payments...");
  await bw("payments",payments,function(p){return p.id;});console.log(" OK");
  await db.collection("config").doc("rates").set({Jardin:35000,Primaria:45000,Secundaria:52000});
  console.log("Rates OK");
  console.log("Creating auth...");
  var cr=0,sk=0,er=0;
  for(var i=0;i<families.length;i++){var f=families[i];var pw="almafuerte"+f.id.replace("FAM-","");
    try{var ex=null;try{ex=await auth.getUserByEmail(f.email);}catch(e){}
    var uid;if(ex){uid=ex.uid;sk++;}else{var u=await auth.createUser({email:f.email,password:pw,displayName:f.responsable});uid=u.uid;cr++;}
    await db.collection("Familias").doc(f.id).update({authUid:uid});}catch(e){er++;}
    if((i+1)%100===0)console.log("  "+(i+1)+"/"+families.length);}
  var sc=(await db.collection("students").get()).size;
  var fc=(await db.collection("Familias").get()).size;
  var pc=(await db.collection("payments").get()).size;
  console.log("DONE! Students:"+sc+" Families:"+fc+" Payments:"+pc+" Auth created:"+cr+" skipped:"+sk+" errors:"+er);
  console.log("Password: almafuerte0001, almafuerte0002, etc.");
  process.exit(0);}
run().catch(function(e){console.error(e);process.exit(1);});
